from datetime import datetime
from elasticsearch import Elasticsearch

# Instantiate Elasticsearch
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

def create_index(index_name):
    es.indices.create(index=index_name, ignore=400)

def delete_index(index_name):
    es.indices.delete(index=index_name, ignore=[400, 404])

def index_document(index_name, doc_type, doc_id, body):
    es.index(index=index_name, doc_type=doc_type, id=doc_id, body=body)

def search(index_name, query):
    return es.search(index=index_name, body=query)

def log_aggregate(index_name):
    query = {"aggs" : { "logs_over_time" : {"date_histogram" : { "field" : "timestamp", "interval" : "1d" } } } }
    return es.search(index=index_name, body=query)

